lessons.solution:
class MessageQueue:
    def __init__(self):
        self.queue = []

    def publish(self, message):
        self.queue.append(message)
        print(f"Published: {message}")

    def consume(self):
        if not self.queue:
            return None
        return self.queue.pop(0)

mq = MessageQueue()
mq.publish("Process Order #123")
mq.publish("Send Email to Alice")
mq.publish("Generate PDF Report")

print("\n--- Consumer Worker ---")
while True:
    task = mq.consume()
    if task is None:
        print("No more tasks!")
        break
    print(f"Working on: {task}")

